<script setup lang="ts">
import {computed,onBeforeUnmount,onMounted,ref} from 'vue';import {useRoute} from 'vue-router';import {Check,Clock,Lock,Loading,Phone,Warning} from '@element-plus/icons-vue';import {getWithdrawal,type Withdrawal,type WithdrawalStatus,withdrawalEventUrl} from '../api/checkout';import {formatEtb} from '../lib/format';
import {useCheckoutSessionStore} from '../stores/session';
const route=useRoute();const session=useCheckoutSessionStore();const withdrawal=ref<Withdrawal>();const loading=ref(true);const error=ref('');let timer:number|undefined;let events:EventSource|undefined;const flow:WithdrawalStatus[]=['accepted','queued','device_assigned','device_started','committed','provider_pending','success'];const index=computed(()=>withdrawal.value?flow.indexOf(withdrawal.value.status):-1);const terminal=computed(()=>withdrawal.value&&['success','failed','unknown','manual_review','cancelled'].includes(withdrawal.value.status));const copy=computed(()=>({accepted:['Request received','We are checking your withdrawal.'],queued:['Waiting for an available payment line','Your request is safely queued.'],device_assigned:['Payment line assigned','We are preparing the Telebirr transfer.'],device_started:['Sending your withdrawal','Please keep this page open.'],committed:['Transfer authorized','The instruction is committed and cannot be automatically retried.'],provider_pending:['Waiting for Telebirr confirmation','The transfer was submitted and will not be duplicated.'],success:['Withdrawal sent','The Telebirr transfer was confirmed.'],failed:['Withdrawal could not be sent','The provider outcome was proven failed. Return to the merchant for next steps.'],unknown:['Confirmation is taking longer','Support is checking the provider result. Do not request a duplicate withdrawal.'],manual_review:['Withdrawal under review','Support is resolving the provider outcome safely.'],cancelled:['Withdrawal cancelled','The request was cancelled before money movement started.']}[withdrawal.value?.status||'accepted']));
async function load(){try{withdrawal.value=await getWithdrawal(String(route.params.reference),String(route.query.token||''));const scenario=String(route.query.scenario||'');if(['success','failed','unknown','manual_review'].includes(scenario))withdrawal.value.status=scenario as WithdrawalStatus}catch(e){error.value=e instanceof Error?e.message:'Unable to load withdrawal'}finally{loading.value=false}}
onMounted(async()=>{session.begin('withdrawal',String(route.params.reference));await load();if((import.meta.env.VITE_USE_MOCKS==='true'||route.params.reference==='demo')&&!route.query.scenario){timer=window.setInterval(()=>{if(!withdrawal.value||terminal.value)return;const i=flow.indexOf(withdrawal.value.status);withdrawal.value.status=flow[Math.min(i+1,flow.length-1)]},2400);return}const reference=String(route.params.reference);const token=String(route.query.token||'');if(typeof EventSource!=='undefined'&&token){events=new EventSource(withdrawalEventUrl(reference,token));events.addEventListener('transfer.status',(event)=>{try{const data=JSON.parse((event as MessageEvent).data);withdrawal.value={reference:data.reference,merchantName:data.merchant_name||withdrawal.value?.merchantName||'Merchant',amount:data.amount,destination:data.account_number_masked,receiverName:data.expected_name,status:data.p2p_status,etaSeconds:data.eta_seconds,createdAt:data.created_at,message:data.message};if(terminal.value)events?.close()}catch{events?.close()}});events.onerror=()=>{events?.close();if(!terminal.value&&!timer)timer=window.setInterval(load,4000)}}else timer=window.setInterval(()=>{if(!terminal.value)load()},4000)});onBeforeUnmount(()=>{if(timer)clearInterval(timer);events?.close()})
</script>
<template><div class="checkout-page"><header class="checkout-header"><div class="brand"><div class="brand-mark">O</div><div><strong>OrbitPay</strong><small>Withdrawal status</small></div></div><div class="secure"><Lock/><span>Secure status page</span></div></header><main class="checkout-main"><div v-if="loading" class="loading"><el-skeleton :rows="6" animated/></div><div v-else-if="error" class="error"><Warning/><h2>Status unavailable</h2><p>{{error}}</p></div><div v-else-if="withdrawal" class="checkout-card withdrawal-card"><aside class="order-pane"><span>Withdrawal from</span><h1>{{withdrawal.merchantName}}</h1><p>Telebirr payout</p><div class="order-amount"><span>You will receive</span><strong>ETB {{formatEtb(withdrawal.amount)}}</strong></div><div class="order-meta"><div><span>Reference</span><b>{{withdrawal.reference}}</b></div><div><span>Destination</span><b>{{withdrawal.destination}}</b></div></div></aside><section class="action-pane"><div :class="['progress-hero',withdrawal.status]"><div class="orb"><div class="pulse"/><el-icon v-if="withdrawal.status==='success'"><Check/></el-icon><el-icon v-else-if="withdrawal.status==='failed'||withdrawal.status==='unknown'||withdrawal.status==='manual_review'"><Warning/></el-icon><el-icon v-else><Loading class="spin"/></el-icon></div><span class="status-pill"><i/> {{withdrawal.status.replace('_',' ')}}</span><h2>{{copy[0]}}</h2><p>{{copy[1]}}</p><div v-if="!terminal" class="eta"><el-icon><Clock/></el-icon><span>Estimated time remaining</span><strong>about {{Math.max(8,withdrawal.etaSeconds-index*8)}} seconds</strong></div></div><div class="steps"><div v-for="(step,i) in ['Request accepted','Payment line assigned','Telebirr transfer','Confirmation']" :key="step" :class="{done:index>=([0,2,3,5][i]),active:(i===0&&index===1)||(i===1&&index===2)||(i===2&&index>=3&&index<5)||(i===3&&index===5)}"><i><Check v-if="index>([0,2,3,5][i])"/><span v-else/></i><div><strong>{{step}}</strong><small>{{i===0?'Request secured':i===1?'A healthy line is selected':i===2?'Never automatically retried after submission':'Provider SMS proves the final result'}}</small></div></div></div><div class="recipient"><el-icon><Phone/></el-icon><span><small>Telebirr receiver</small><strong>{{withdrawal.receiverName}} · {{withdrawal.destination}}</strong></span></div><p class="safe-note"><el-icon><Lock/></el-icon> You may close this page. The merchant will receive the final status automatically.</p></section></div></main><footer class="checkout-footer">OrbitPay never asks for your Telebirr PIN or verification code</footer></div></template>
<style scoped>
.loading,.error{width:min(92vw,560px);padding:30px;background:#fff;border:1px solid var(--line);border-radius:17px}.error{text-align:center}.error svg{width:35px;color:var(--danger)}.progress-hero{text-align:center}.orb{width:76px;height:76px;display:grid;place-items:center;border-radius:50%;background:#eeeeff;color:var(--primary);font-size:30px;margin:0 auto 15px;position:relative}.orb .pulse{position:absolute;inset:-8px;border-radius:50%;border:1px solid #d4d5fa;animation:pulse 1.8s ease-out infinite}.progress-hero.success .orb{background:#e5f7f2;color:var(--teal)}.progress-hero.failed .orb,.progress-hero.unknown .orb,.progress-hero.manual_review .orb{background:#ffebee;color:var(--danger)}.progress-hero h2{font:800 23px 'Manrope';letter-spacing:-.04em;margin:14px 0 6px}.progress-hero>p{font-size:11px;color:var(--muted);margin:0}.eta{display:flex;align-items:center;justify-content:center;gap:6px;margin-top:12px;font-size:9px;color:var(--muted)}.eta strong{color:var(--primary)}.steps{margin:22px 0 15px}.steps>div{display:grid;grid-template-columns:27px 1fr;gap:10px;min-height:52px;position:relative}.steps>div:not(:last-child):after{content:'';position:absolute;left:12px;top:25px;bottom:-1px;width:1px;background:var(--line)}.steps i{width:25px;height:25px;border:1px solid #d8dce5;border-radius:50%;display:grid;place-items:center;color:white;z-index:1;background:#fff}.steps i svg{width:13px}.steps i span{width:7px;height:7px;border-radius:50%;background:#d6dae3}.steps .done i{background:var(--teal);border-color:var(--teal)}.steps .active i{border:6px solid #ddddfb;background:var(--primary)}.steps .active i span{display:none}.steps strong,.steps small{display:block;text-align:left}.steps strong{font-size:11px;margin-top:3px}.steps small{font-size:9px;color:var(--muted);margin-top:3px;line-height:1.35}.recipient{display:flex;gap:10px;align-items:center;background:#f6f7fa;border-radius:9px;padding:11px}.recipient>.el-icon{color:var(--primary)}.recipient span{text-align:left}.recipient small,.recipient strong{display:block}.recipient small{font-size:8px;text-transform:uppercase;color:var(--muted)}.recipient strong{font-size:10px;margin-top:3px}.safe-note{display:flex;align-items:center;justify-content:center;gap:5px;text-align:center;color:var(--muted);font-size:8px;margin:12px 0 0}.spin{animation:spin 1.2s linear infinite}@keyframes spin{to{transform:rotate(360deg)}}@keyframes pulse{0%{transform:scale(.85);opacity:1}100%{transform:scale(1.22);opacity:0}}
</style>
